"use client";
import { useState } from "react";

export default function Home() {
  const [walletAddress, setWalletAddress] = useState("");
  const [activeDrift, setActiveDrift] = useState("streaming");
  
  // Form state
  const [recipient, setRecipient] = useState("");
  const [amount, setAmount] = useState("");
  const [duration, setDuration] = useState("");

  const connectWallet = async () => {
    if (typeof window !== "undefined" && window.ethereum) {
      try {
        const accounts = await window.ethereum.request({ method: "eth_requestAccounts" });
        const address = accounts[0];
        setWalletAddress(address.slice(0, 6) + "..." + address.slice(-4));
      } catch (err) {
        console.error("Connection failed", err);
      }
    } else {
      alert("MetaMask not found! Please install it.");
    }
  };

  const handleDeploy = (e: React.FormEvent) => {
    e.preventDefault();
    if (!walletAddress) {
      alert("Connect your wallet first!");
      return;
    }
    alert(`Deploying ${activeDrift} drift: ${amount} ARC to ${recipient} for ${duration} hours!`);
  };

  return (
    <main className="min-h-screen bg-[#07090E] text-white font-sans selection:bg-blue-500/30 pb-20">
      {/* Navbar */}
      <nav className="flex justify-between items-center p-6 mb-8">
        <div className="flex items-center gap-3">
          <img src="/arc-logo.jpg" alt="ARC" className="h-8 rounded-md object-contain" />
          <div className="text-2xl font-bold tracking-tight">
            ARC <span className="text-gray-500 font-medium">Drift</span>
          </div>
        </div>
        <button
          onClick={connectWallet}
          className="bg-[#7B5EFA] hover:bg-[#684be3] px-6 py-2.5 rounded-xl font-semibold transition-all shadow-[0_0_20px_rgba(123,94,250,0.3)] text-sm"
        >
          {walletAddress ? walletAddress : "Connect Wallet"}
        </button>
      </nav>
      
      {/* Main Container */}
      <div className="flex flex-col items-center px-4">
        {/* The Glass Card */}
        <div className="w-full max-w-[500px] bg-[#0E121A] border border-[#1C2333] rounded-[2rem] p-8 shadow-2xl relative overflow-hidden">
          
          {/* Header Row */}
          <div className="flex items-center gap-4 mb-8">
            <div className="w-12 h-12 rounded-2xl bg-[#1C2333] flex items-center justify-center text-blue-400 font-light text-3xl">
              +
            </div>
            <h2 className="text-2xl font-bold tracking-wide">Deploy Drift</h2>
            <span className="ml-auto px-3 py-1.5 rounded-full border border-gray-700 bg-gray-800/40 text-[10px] font-bold text-gray-400 tracking-widest uppercase">
              Simulation V2.4
            </span>
          </div>

          {/* 2x2 Grid Selection */}
          <div className="grid grid-cols-2 gap-4 mb-8">
            <DriftCard 
              id="delayed" title="Delayed Transfer" icon="🕒" 
              isActive={activeDrift === "delayed"} onClick={() => setActiveDrift("delayed")} 
            />
            <DriftCard 
              id="streaming" title="Streaming Payment" icon="🌊" 
              isActive={activeDrift === "streaming"} onClick={() => setActiveDrift("streaming")} 
            />
            <DriftCard 
              id="cancelable" title="Cancelable Transfer" icon="🚫" 
              isActive={activeDrift === "cancelable"} onClick={() => setActiveDrift("cancelable")} 
            />
            <DriftCard 
              id="recurring" title="Recurring Payment" icon="🔁" 
              isActive={activeDrift === "recurring"} onClick={() => setActiveDrift("recurring")} 
            />
          </div>

          {/* Form Inputs */}
          <form onSubmit={handleDeploy} className="flex flex-col gap-6">
            <div>
              <label className="block text-[#64748B] text-xs font-bold mb-2 tracking-widest uppercase">Recipient Address</label>
              <div className="relative">
                <input 
                  type="text" placeholder="0x..." 
                  value={recipient} onChange={(e) => setRecipient(e.target.value)}
                  className="w-full bg-[#151B28] border border-[#232D42] text-gray-300 p-4 rounded-xl focus:outline-none focus:border-[#7B5EFA] transition-colors font-mono text-sm"
                  required
                />
                <span className="absolute right-4 top-4 text-gray-600">〰️</span>
              </div>
            </div>
            
            <div className="flex gap-4">
              <div className="w-1/2">
                <label className="block text-[#64748B] text-xs font-bold mb-2 tracking-widest uppercase">Amount (ARC)</label>
                <input 
                  type="number" placeholder="1" 
                  value={amount} onChange={(e) => setAmount(e.target.value)}
                  className="w-full bg-[#151B28] border border-[#232D42] text-gray-300 p-4 rounded-xl focus:outline-none focus:border-[#7B5EFA] transition-colors font-mono text-sm"
                  required
                />
              </div>
              <div className="w-1/2">
                <label className="block text-[#64748B] text-xs font-bold mb-2 tracking-widest uppercase">Duration (HRS)</label>
                <input 
                  type="number" placeholder="24" 
                  value={duration} onChange={(e) => setDuration(e.target.value)}
                  className="w-full bg-[#151B28] border border-[#232D42] text-gray-300 p-4 rounded-xl focus:outline-none focus:border-[#7B5EFA] transition-colors font-mono text-sm"
                  required
                />
              </div>
            </div>

            <button 
              type="submit"
              className="w-full bg-[#7B5EFA] hover:bg-[#684be3] text-white font-bold py-4 rounded-xl mt-4 transition-all shadow-[0_0_20px_rgba(123,94,250,0.2)] text-lg"
            >
              Initialize Drift
            </button>
          </form>
        </div>
      </div>
    </main>
  );
}

// Helper component for the grid boxes to keep the code clean
function DriftCard({ id, title, icon, isActive, onClick }: any) {
  return (
    <div 
      onClick={onClick}
      className={`cursor-pointer p-4 rounded-2xl border transition-all duration-200 flex flex-col h-32 justify-end relative overflow-hidden
        ${isActive 
          ? 'bg-[#18243E]/50 border-[#3B82F6] shadow-[0_0_15px_rgba(59,130,246,0.15)]' 
          : 'bg-[#151B28] border-[#232D42] hover:border-gray-600'
        }`}
    >
      <div className={`absolute top-4 left-4 w-10 h-10 rounded-full flex items-center justify-center text-lg
        ${isActive ? 'bg-[#3B82F6]/20 text-[#3B82F6]' : 'bg-[#1C2333] text-gray-400'}`}>
        {icon}
      </div>
      <h3 className={`font-semibold text-sm ${isActive ? 'text-white' : 'text-gray-400'}`}>
        {title.split(' ').map((word: string, i: number) => <div key={i}>{word}</div>)}
      </h3>
    </div>
  );
}